//! OwnSome — OS competition kernel for RISC-V and LoongArch64
//!
//! Based on NighthawkOS (https://gitlab.eduxiji.net/T202518123995755-2974),
//! an async coroutine-based monolithic kernel written in Rust.
//!
//! Key improvements over the base:
//! - Scheduler syscalls (sched_setscheduler/getparam/getscheduler) from stub → full implementation
//! - Memory management: mremap with MAYMOVE/FIXED/DONTUNMAP support
//! - Threading: robust_list storage for NPTL compatibility
//! - Network: background net_poll_init, recvfrom poll fix, iperf accept deadlock fix
//! - Panic elimination: 7 kernel panics fixed (nlink, signal shift, user_ptr, ENOSYS, dentry, ext4, syscall 452)
//! - fanotify: removed unimplemented!() panics, added init flags support, ONDIR event filter
//! - Syscall additions: preadv/pwritev, getpriority/setpriority, sched_get_priority_max/min, fcntl locks, syslog read
//! - LTP stability: TFAIL significantly reduced, 0 kernel panics in full test runs
//!
//! References:
//! - RocketOS (T202510213995926-2475): sched_get_priority, robust_list, FIFO scheduler design
//! - Chronix (T202518123995568-675): mremap implementation design
//! - NoAxiom (T202510336995214-148): clean socket flag handling pattern
//!

OUTPUT_ARCH(riscv)
ENTRY(_start)

SECTIONS
{
    .text : ALIGN(4K) {
        _skernel = .;
        _stext = .;
        *(.text.entry)

        . = ALIGN(4K);
        _strampoline = .;
        *(.text.trampoline)
        _etrampoline = .;

        . = ALIGN(4K);
        *(.text .text.*)
        _etext = .;
    } > VIRT AT> RAM

    .rodata : ALIGN(4K) {
        _srodata = .;
        *(.rodata .rodata.*)
        *(.srodata .srodata.*)
        _erodata = .;
    } > VIRT AT> RAM

    .data : ALIGN(4K) {
        _sdata = .;
        *(.data .data.*)
        *(.sdata .sdata.*)
        *(.got)
        _edata = .;
    } > VIRT AT> RAM

    .bss : ALIGN(4K) {
        _sbss = .;
        *(.bss.stack)
        _kbss = .;
        *(.bss .bss.*)
        *(.sbss .sbss.*)
        _ebss = .;
    } > VIRT AT> RAM

    . = ALIGN(4K);
    _ekernel = .;

    /DISCARD/ : {
        *(.eh_frame)
    }
}

MEMORY
{
    VIRT : ORIGIN = %VIRT_START%, LENGTH = %RAM_SIZE%
    RAM : ORIGIN = %RAM_START%, LENGTH = %RAM_SIZE%
}

use std::{env, fs, path::PathBuf};

use config::mm::{KERNEL_RAM_OFFSET, KERNEL_START_PHYS, RAM_SIZE};

fn main() {
    #![allow(non_snake_case)]

    let manifest_dir = env::var("CARGO_MANIFEST_DIR").unwrap();
    let out_dir = env::var("OUT_DIR").unwrap();
    let target_arch = env::var("CARGO_CFG_TARGET_ARCH").unwrap();
    let target_triple = env::var("TARGET").unwrap();
    let compile_profile = env::var("PROFILE").unwrap();

    let ram_size = RAM_SIZE - KERNEL_RAM_OFFSET;
    let target_arch_acronym = match target_arch.as_str() {
        "riscv64" => "rv",
        "loongarch64" => "la",
        _ => panic!("Unsupported target architecture"),
    };

    // Note: Remember to copy the constants from `lib/config/src/mm.rs` to here.
    // This is a workaround for the fact that the build script is compiled for the host
    // architecture, not the target architecture of the kernel.
    let VIRT_START: usize = match target_arch.as_str() {
        "riscv64" => 0xffff_ffc0_8000_0000,
        "loongarch64" => 0x9000_0000_8000_0000,
        _ => panic!("Unsupported target architecture"),
    };
    let KERNEL_START: usize = VIRT_START + KERNEL_RAM_OFFSET;

    // Generate the linker script.
    let link_script = fs::read_to_string(PathBuf::from(manifest_dir.clone()).join("linker.ld"))
        .unwrap()
        .replace("%RAM_START%", &KERNEL_START_PHYS.to_string())
        .replace("%VIRT_START%", &KERNEL_START.to_string())
        .replace("%RAM_SIZE%", &ram_size.to_string());
    let linker_script_dest = PathBuf::from(out_dir).join("linker.ld");
    fs::write(&linker_script_dest, link_script).unwrap();
    println!("cargo:rustc-link-arg=-T{}", linker_script_dest.display());

    let linkapp =
        fs::read_to_string(PathBuf::from(manifest_dir.clone()).join("src/linkapp.asm.tmpl"))
            .unwrap()
            .replace("<cargo-target>", &target_triple)
            .replace("<cargo-profile>", &compile_profile)
            .replace("<cargo-target-acronym>", target_arch_acronym);
    let linkapp_dest = PathBuf::from(manifest_dir).join("src/linkapp.asm");
    fs::write(&linkapp_dest, linkapp).unwrap();
}

